#!/usr/bin/env dotnet
// Explore Friday the 13th in the proleptic Gregorian calendar

// Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateTime(1, 1, 13); // start on the 13th of January, year 1
while (date.DayOfWeek != DayOfWeek.Friday)
{
    date = date.AddMonths(1);
}
Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// Count Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        if (new DateTime(year, month, 13).DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}
Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// Bonus: which day-of-week lands on the 13th most often?
var dayCounts = new int[7];
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        dayCounts[(int)new DateTime(year, month, 13).DayOfWeek]++;
    }
}

Console.WriteLine("\n13th-of-month distribution over 400 years:");
foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
{
    Console.WriteLine($"  {dow,-10} {dayCounts[(int)dow]}");
}

